 name: Coverage Suite

-# Runs full test suite with coverage every 2 hours via sharding.
+# Runs full test suite with coverage after each merge to main.
 # Updates the README coverage badge via gist.
+# Failures are attributed to the triggering commit/PR for accountability.

 on:
-  schedule:
-    - cron: '15 */2 * * *'  # Every 2 hours at :15
+  push:
+    branches: [main]
+    paths:
+      - 'web/src/**'
+      - 'web/package.json'
+      - 'web/package-lock.json'
+      - 'web/vite.config.ts'
   workflow_dispatch:

+concurrency:
+  group: coverage-suite
+  cancel-in-progress: true
+
 permissions:
   contents: read

